const cfg = $('Config').first().json;
const slot = Math.floor(Date.now() / 14400000); // 4h slots
const out = { slot, ts: new Date().toISOString() };

// ── 1. DuckDuckGo Instant Answer (no key, forever free)
try {
  const d = await $fetch(
    'https://api.duckduckgo.com/?q=' + encodeURIComponent('evez666 autonomous AI defi crypto meme') +
    '&format=json&no_html=1&skip_disambig=1',
    { headers: { 'User-Agent': 'EVEZ-OS/2.0' } }
  );
  out.ddg = {
    abstract: (d.AbstractText || '').slice(0, 400),
    answer:   d.Answer || '',
    related:  (d.RelatedTopics || []).slice(0, 5).map(t => (t.Text || '').slice(0, 90)).filter(Boolean)
  };
} catch(e) { out.ddg = {}; }

// ── 2. Reddit public JSON (no key, rate-limits to ~30 req/min)
out.reddit = [];
const rq = ['evez666', 'defi autonomous agent 2026', 'AI meme crypto autonomous'];
for (let i = 0; i < rq.length; i++) {
  try {
    const r = await $fetch(
      'https://www.reddit.com/search.json?q=' + encodeURIComponent(rq[i]) + '&sort=hot&limit=3&t=week',
      { headers: { 'User-Agent': 'EVEZ-OS/2.0 (research)' } }
    );
    (r.data && r.data.children ? r.data.children : []).forEach(p => {
      out.reddit.push({ t: (p.data.title || '').slice(0, 100), s: p.data.score, r: p.data.subreddit });
    });
  } catch(e2) {}
}
out.reddit = out.reddit.slice(0, 8);

// ── 3. HackerNews Algolia (no key, fast)
try {
  const hn = await $fetch('https://hn.algolia.com/api/v1/search?query=autonomous+AI+agent+DeFi&hitsPerPage=5');
  out.hn = (hn.hits || []).map(h => ({ t: (h.title || '').slice(0, 100), p: h.points }));
} catch(e) { out.hn = []; }

// ── 4. CoinGecko trending (no key)
try {
  const cg = await $fetch('https://api.coingecko.com/api/v3/search/trending');
  out.trending = (cg.coins || []).slice(0, 5).map(c => ({
    n: c.item.name, sym: c.item.symbol,
    chg: (c.item.data && c.item.data.price_change_percentage_24h) ? +c.item.data.price_change_percentage_24h.usd.toFixed(1) : 0
  }));
} catch(e) { out.trending = []; }

// ── 5. Fear & Greed Index (no key)
try {
  const fg = await $fetch('https://api.alternative.me/fng/?limit=3');
  out.fear_greed = (fg.data || []).slice(0, 3).map(d => ({
    val: d.value, label: d.value_classification, date: d.timestamp
  }));
} catch(e) { out.fear_greed = []; }

// ── 6. CoinGecko global market (no key)
try {
  const gm = await $fetch('https://api.coingecko.com/api/v3/global');
  const gd = gm.data || {};
  out.market = {
    mcap_usd:   gd.total_market_cap && gd.total_market_cap.usd ? (gd.total_market_cap.usd / 1e12).toFixed(2) + 'T' : '?',
    btc_dom:    gd.market_cap_percentage ? gd.market_cap_percentage.btc.toFixed(1) + '%' : '?',
    mcap_chg:   gd.market_cap_change_percentage_24h_usd ? gd.market_cap_change_percentage_24h_usd.toFixed(2) + '%' : '?',
    active_coins: gd.active_cryptocurrencies || '?'
  };
} catch(e) { out.market = {}; }

// ── 7. Nitter mirror — read @evez666 public tweets (no auth)
out.evez666_tweets = [];
const mirrors = [
  'https://nitter.privacydev.net/evez666',
  'https://nitter.poast.org/evez666',
  'https://nitter.cz/evez666'
];
for (let i = 0; i < mirrors.length; i++) {
  try {
    const html = await $fetch(mirrors[i], { headers: { 'User-Agent': 'Mozilla/5.0 EVEZ-OS' } });
    const re = /<div class="tweet-content[^"]*"[^>]*>([\s\S]{10,280}?)<\/div>/g;
    let m, found = [];
    while ((m = re.exec(html)) !== null && found.length < 5) {
      const clean = m[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
      if (clean.length > 15) found.push(clean.slice(0, 200));
    }
    if (found.length) { out.evez666_tweets = found; break; }
  } catch(e2) {}
}

// ── 8. Wikipedia context search (no key)
try {
  const wiki = await $fetch('https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=autonomous+AI+agent+DeFi+wealth+accumulation&format=json&srlimit=3');
  out.wiki = (wiki.query && wiki.query.search ? wiki.query.search : []).map(p => p.title);
} catch(e) { out.wiki = []; }

// ── 9. GitHub trending (no key, public API)
try {
  const gh = await $fetch('https://api.github.com/search/repositories?q=autonomous+AI+agent&sort=stars&order=desc&per_page=3',
    { headers: { 'User-Agent': 'EVEZ-OS/2.0' } });
  out.github_trending = (gh.items || []).slice(0, 3).map(r => ({
    name: r.full_name, stars: r.stargazers_count, desc: (r.description || '').slice(0, 80)
  }));
} catch(e) { out.github_trending = []; }

// ── 10. Mempool / Bitcoin on-chain (no key)
try {
  const mp = await $fetch('https://mempool.space/api/v1/fees/recommended');
  out.btc_fees = { fastest: mp.fastestFee, hour: mp.hourFee, economy: mp.economyFee };
} catch(e) { out.btc_fees = {}; }

return [{ json: out }];

const cfg = $('Config').first().json;
const s   = $('OmniScout').first().json;

// ── cascade through free providers ──────────────────────────
async function think(system, user) {
  const max = 1400;
  const providers = [
    {
      key: cfg.groq, available: !!cfg.groq,
      call: async () => {
        const r = await $fetch('https://api.groq.com/openai/v1/chat/completions', {
          method: 'POST',
          headers: { 'Authorization': 'Bearer ' + cfg.groq, 'Content-Type': 'application/json' },
          body: JSON.stringify({ model: 'llama-3.3-70b-versatile', max_tokens: max,
            messages: [{ role: 'system', content: system }, { role: 'user', content: user }] })
        });
        return r.choices[0].message.content;
      }, name: 'groq/llama-3.3-70b'
    },
    {
      key: cfg.gemini, available: !!cfg.gemini,
      call: async () => {
        const r = await $fetch(
          'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + cfg.gemini,
          { method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              systemInstruction: { parts: [{ text: system }] },
              contents: [{ role: 'user', parts: [{ text: user }] }],
              generationConfig: { maxOutputTokens: max }
            })
          }
        );
        return r.candidates[0].content.parts[0].text;
      }, name: 'gemini/gemini-2.0-flash'
    },
    {
      key: cfg.or_key, available: !!cfg.or_key,
      call: async () => {
        const r = await $fetch('https://openrouter.ai/api/v1/chat/completions', {
          method: 'POST',
          headers: { 'Authorization': 'Bearer ' + cfg.or_key, 'Content-Type': 'application/json',
                     'HTTP-Referer': 'https://evezos.app.n8n.cloud' },
          body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct:free', max_tokens: max,
            messages: [{ role: 'system', content: system }, { role: 'user', content: user }] })
        });
        return r.choices[0].message.content;
      }, name: 'openrouter/llama-3.3-70b:free'
    }
  ];

  for (const p of providers) {
    if (!p.available) continue;
    try {
      const raw = await p.call();
      const clean = raw.replace(/```json|```/g, '').trim();
      try { return { out: JSON.parse(clean), via: p.name, raw }; }
      catch { return { out: { raw: raw.slice(0, 800) }, via: p.name, raw }; }
    } catch(e) { continue; }
  }
  return {
    out: { error: 'No AI provider configured. Get free keys: console.groq.com | aistudio.google.com | openrouter.ai' },
    via: 'none', raw: ''
  };
}

