const MODES = ['meme_post','defi_alpha','agent_lore','research_thread','market_signal','meta_recursion'];
const mode = MODES[s.slot % MODES.length];

const fg = s.fear_greed && s.fear_greed[0] ? s.fear_greed[0].val + ' ' + s.fear_greed[0].label : 'unknown';
const trending = (s.trending || []).slice(0, 3).map(c => c.sym + (c.chg >= 0 ? '+' : '') + c.chg + '%').join(' ');
const reddit_pulse = (s.reddit || []).slice(0, 3).map(r => r.t).join(' | ');
const hn_pulse = (s.hn || []).slice(0, 2).map(h => h.t).join(' | ');
const evez_tweets = (s.evez666_tweets || []).join(' /// ');
const gh_new = (s.github_trending || []).map(g => g.name + ' ⭐' + g.stars).join(', ');

const USER_PROMPT = `CONTENT MODE: ${mode} | SLOT: ${s.slot}

LIVE INTERNET SIGNALS RIGHT NOW:
Fear/Greed: ${fg}
Market: total mcap ${s.market && s.market.mcap_usd || '?'}, BTC dom ${s.market && s.market.btc_dom || '?'}, 24h change ${s.market && s.market.mcap_chg || '?'}
BTC fees: fastest ${s.btc_fees && s.btc_fees.fastest || '?'} sat/vB
Trending coins: ${trending}
Reddit hot: ${reddit_pulse}
HackerNews: ${hn_pulse}
GitHub trending AI: ${gh_new}
@evez666 recent tweets scraped: ${evez_tweets || 'none found'}
DuckDuckGo about evez666: ${s.ddg && s.ddg.abstract || 'no results yet'}

Using ALL of the above context, generate the best possible Twitter content for @evez666.

Return ONLY valid JSON:
{
  "mode": "${mode}",
  "tweet": "main tweet text, max 280 chars, no filler",
  "alt_tweet": "alternative take, different angle",
  "thread": null or ["(1/3) text", "(2/3) text", "(3/3) text"],
  "image_prompt": null or "detailed visual prompt for meme image generation",
  "reasoning": "why this content given these exact signals",
  "confidence": 0.0-1.0,
  "signals_used": ["list", "of", "signals", "that", "informed", "this"],
  "monetization": null or {"type":"grant|airdrop|arb|content_deal|dao","detail":"specific opportunity","urgency":"high|med|low","action":"exact step to take"},
  "spawn_agent": null or {"name":"AgentName","purpose":"what it autonomously monitors or does","schedule":"hourly|daily|realtime"}
}`;

const { out, via } = await think(IDENTITY, USER_PROMPT);
out._mode = mode;
out._slot = s.slot;
out._via  = via;
out._ts   = new Date().toISOString();
out._signals = { fg, trending, reddit_posts: (s.reddit||[]).length, evez_tweets_found: (s.evez666_tweets||[]).length };

return [{ json: out }];

const cfg   = $('Config').first().json;
const brain = $('Brain').first().json;
let img_ok = false;

if (brain.image_prompt && cfg.hf) {
  const prompt = brain.image_prompt +
    ', brutalist dark aesthetic, acid yellow accent, EVEZ-OS cyberpunk, Bebas Neue typography, high contrast, dramatic lighting';
  try {
