    });
    img_ok = true;
  } catch(e) {}
}

const tweet = brain.tweet || brain.alt_tweet || 'EVEZ-OS tick. PID 335. still building.';

return [{ json: {
  tweet:       tweet.slice(0, 280),
  alt:         (brain.alt_tweet || '').slice(0, 280),
  thread:      brain.thread || null,
  img_prompt:  brain.image_prompt || null,
  img_ok,
  mode:        brain._mode,
  via:         brain._via,
  monetization: brain.monetization || null,
  spawn_agent: brain.spawn_agent || null,
  confidence:  brain.confidence || 0,
  reasoning:   brain.reasoning || '',
  signals:     brain._signals || {},
  ready:       !!brain.tweet,
  ts:          new Date().toISOString()
}}];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;
const hasCreds = !!(cfg.tw_ak && cfg.tw_as && cfg.tw_at && cfg.tw_ats);
const autoPost = cfg.post === 'true';

const result = {
  posted: false, tweet_id: null,
