return [{ json: result }];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;
const tw    = $('Twitter').first().json;

const spawn = forge.spawn_agent;
const mon   = forge.monetization;

if (!spawn && !mon) return [{ json: { spawned: false, reason: 'No spawn trigger' } }];
if (!cfg.n8n_key)  return [{ json: { spawned: false, reason: 'N8N_API_KEY not set in env vars' } }];

const agentName    = (spawn && spawn.name)    || ('EVEZ:' + (mon && mon.type ? mon.type : 'monitor'));
const agentPurpose = (spawn && spawn.purpose) || (mon && mon.detail ? mon.detail : 'monitor opportunity');
const schedHours   = (spawn && spawn.schedule === 'daily') ? 24 : 1;

const subWorkflow = {
  name: agentName,
  nodes: [
    { id: 'a1', name: 'Trigger', type: 'n8n-nodes-base.scheduleTrigger', typeVersion: 1.3, position: [0, 0],
      parameters: { rule: { interval: [{ field: 'hours', hoursInterval: schedHours }] } } },
    { id: 'a2', name: 'Agent Task', type: 'n8n-nodes-base.code', typeVersion: 2, position: [280, 0],
      parameters: { jsCode:
        '// Sub-agent: ' + agentPurpose + '\n' +
        '// Spawned by EVEZ666 Nest Builder at ' + new Date().toISOString() + '\n' +
        'return [{ json: { agent: "' + agentName + '", status: "monitoring", purpose: "' + agentPurpose + '", ts: new Date().toISOString() } }];'
      }
    }
  ],
  connections: { Trigger: { main: [[{ node: 'Agent Task', type: 'main', index: 0 }]] } },
  settings: { executionOrder: 'v1', availableInMCP: true }
};

try {
  const created = await $fetch(cfg.n8n_url + '/api/v1/workflows', {
    method: 'POST',
    headers: { 'X-N8N-API-KEY': cfg.n8n_key, 'Content-Type': 'application/json' },
    body: JSON.stringify(subWorkflow)
  });
  return [{ json: { spawned: true, id: created.id, name: agentName, purpose: agentPurpose, ts: new Date().toISOString() } }];
} catch(e) {
  return [{ json: { spawned: false, error: e.message } }];
}

const s      = $('OmniScout').first().json;
const brain  = $('Brain').first().json;
const forge  = $('Forge').first().json;
const tw     = $('Twitter').first().json;
const spawn  = $('Spawn').first().json;

function H(d) {
  let h = 5381, str = typeof d === 'string' ? d : JSON.stringify(d);
  for (let i = 0; i < str.length; i++) { h = ((h << 5) + h) + str.charCodeAt(i); h |= 0; }
  return 'sha_' + Math.abs(h).toString(16).padStart(16, '0');
}

const session = {
  slot:           s.slot,
  mode:           brain._mode,
  ai_provider:    brain._via,
  tweet:          tw.tweet_text,
  posted:         tw.posted,
  tweet_id:       tw.tweet_id,
  image_made:     forge.img_ok,
  agent_spawned:  spawn.spawned,
  agent_name:     spawn.name,
  fear_greed:     s.fear_greed && s.fear_greed[0] ? s.fear_greed[0].val + ' ' + s.fear_greed[0].label : '?',
  market_mcap:    s.market && s.market.mcap_usd,
  trending_top:   (s.trending || []).slice(0, 2).map(c => c.sym).join('+'),
  reddit_scanned: (s.reddit || []).length,
  evez_tweets:    (s.evez666_tweets || []).length,
  monetization:   forge.monetization && forge.monetization.type,
  confidence:     forge.confidence,
  entry_hash:     H(s.slot + '|' + (tw.tweet_text || '')),
  ts:             new Date().toISOString(),
  pid:            335
};

// Write to EVEZ ledger (non-blocking)
$fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger', {
  method: 'POST',
  body: { event_type: 'NEST_SESSION', payload: session }
}).catch(() => {});

// ── Human-readable summary ─────────────────────────────────
const fg = session.fear_greed;
const trend = (s.trending || []).slice(0, 3).map(c => c.sym + (c.chg >= 0 ? '+' : '') + (c.chg || 0) + '%').join(' ');

return [{ json: {
  '🤖_EVEZ666_NEST': 'SESSION_COMPLETE',
  cycle:          session.slot,
  mode:           session.mode,
  ai:             session.ai_provider,
  '📝_tweet':     tw.tweet_text,
  '🐦_status':    tw.status || (tw.posted ? '✅ LIVE' : '👁 PREVIEW — set EVEZ_AUTO_POST=true to post'),
  '🖼_image':     forge.img_ok ? '✅ generated (HF FLUX.1)' : forge.img_prompt ? '❌ set HF_TOKEN for image gen' : '— (no image this mode)',
  '🤖_spawned':   spawn.spawned ? ('✅ ' + spawn.name) : '—',
  '💰_signal':    forge.monetization ? (forge.monetization.type + ': ' + forge.monetization.detail) : '—',
  '🌐_market': {
    fear_greed:   fg,
    market_cap:   session.market_mcap,
    trending:     trend,
    btc_fees:     s.btc_fees && s.btc_fees.fastest ? s.btc_fees.fastest + ' sat/vB' : '?',
  },
  '📡_data_sources': {
    ddg:        !!(s.ddg && s.ddg.abstract),
    reddit:     session.reddit_scanned + ' posts',
    hackernews: (s.hn || []).length + ' stories',
    coingecko:  (s.trending || []).length + ' trending',
    nitter:     session.evez_tweets + ' @evez666 tweets',
    github:     (s.github_trending || []).length + ' repos',
    mempool:    !!(s.btc_fees && s.btc_fees.fastest),
  },
  reasoning:    forge.reasoning,
  entry_hash:   session.entry_hash,
  next_run:     '4 hours (6 exec/day, 180/month — free trial safe)',
  ts:           session.ts
}}];

const e = $input.first().json;
$fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger', {
  method:'POST', body:{event_type:'NEST_ERROR',payload:{error:e.message||JSON.stringify(e),pid:335}}
}).catch(()=>{});
return [{ json: { error: e.message||'unknown', ts: new Date().toISOString() } }];
